       \DiagramSquare {
        nw =  \pi _1^* E \times _{ B \times B } \pi _2^* F ,
        sw =  B \times B ,
        south =  \otimes ,
        ne =  E \otimes _{ B } F ,
        se = B,
        north/style = {->,exists},
        east/style = {|->,exists},
        west/style = {|->},
        height = 1.5cm,
        width = 3cm,
      }



    Note: the cocartesian lift above does not correspond to composition in \mathbf {Cat} except in the discrete case.

