\begin {tikzpicture}[diagram]
  \node  (0) {$F { \mathopen {} \left ( f;g \right ) \mathclose {}} ;  \alpha _{ Z } $};
  \node [right = 4.5cm of 0] (1) {$ { \mathopen {} \left ( Ff;Fg \right ) \mathclose {}} ; \alpha _{ Z } $};
  \node [right = 6cm of 1] (2) {$Ff; { \mathopen {} \left ( Fg; \alpha _{ Z } \right ) \mathclose {}} $};

  \node [below = of 0] (3) {$Ff; { \mathopen {} \left ( \alpha _{ Y } ;Gg \right ) \mathclose {}} $};
  \node [right = 6 cm of 3] (4) {$ { \mathopen {} \left ( Ff; \alpha _{ Y } \right ) \mathclose {}} ;Gg$};
  \node [below = of 2] (5) {$ { \mathopen {} \left ( \alpha _{ X } ;Gf \right ) \mathclose {}} ;Gg$};

  \node [below = of 3] (6) {$ \alpha _{ X } ; { \mathopen {} \left ( Gf;Gg \right ) \mathclose {}} $};
  \node [right = 5.5cm of 6] (7) {$ \alpha _{ X } ;G { \mathopen {} \left ( f;g \right ) \mathclose {}} $};

  \draw [->] (0) to node[above] {$ \mathsf { seq } _{ F } \, f \, g; \alpha _Z$} (1);
  \draw [->] (1) to node[above] {$ { \mathopen {} \left ( \mathsf { assoc } _{ \mathcal {C} } \, { \mathopen {} \left ( Ff \right ) \mathclose {}} \, { \mathopen {} \left ( Fg \right ) \mathclose {}} \, \alpha _Z \right ) \mathclose {}} ^{ -1 } $} (2);
  \draw [->] (2) to[out = 270, in = 80, looseness = 0.3] node[upright desc] {$Ff; \alpha _{ g } $} (3);
  \draw [->] (3) to node[above] {$ \mathsf { assoc } _{ \mathcal {C} } \, { \mathopen {} \left ( Ff \right ) \mathclose {}} \, \alpha _{ Y } \, { \mathopen {} \left ( Gg \right ) \mathclose {}} $} (4);
  \draw [->] (4) to node[above] {$ \alpha _f;Gg$} (5);
  \draw [->] (5) to[out = 270, in = 80, looseness = 0.3] node[upright desc] {$ { \mathopen {} \left ( \mathsf { assoc } _{ \mathcal {C} } \, \alpha _{ X } \, { \mathopen {} \left ( Gf \right ) \mathclose {}} \, { \mathopen {} \left ( Gg \right ) \mathclose {}} \right ) \mathclose {}} ^{ -1 } $} (6);

  \draw [->] (6) to node[above] {$ \alpha _{ X } ; { \mathopen {} \left ( \mathsf { seq } _{ G } \, f \, g \right ) \mathclose {}} ^{ -1 } $} (7);

\end {tikzpicture}
